```class Solution {
public:
    int maxAbsValExpr(vector<int>& arr1, vector<int>& arr2) {
        int n = arr1.size();
        int max_abs_val = INT_MIN;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                int diff1 = abs(arr1[i] - arr1[j]);
                int diff2 = abs(arr2[i] - arr2[j]);
                int diff3 = abs(i - j);
                max_abs_val = max(max_abs_val, diff1 + diff2 + diff3);
            }
        }
        return max_abs_val;
    }
};
```

